import React, { useState, useEffect } from 'react';
import { productService } from '../../services/productService';
import { userService } from '../../services/userService';
import { orderService } from '../../services/orderService';
import toast from 'react-hot-toast';
import './AdminDashboard.css';

const AdminDashboard = () => {
  const [products, setProducts] = useState([]);
  const [users, setUsers] = useState([]);
  const [orders, setOrders] = useState([]);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showProductForm, setShowProductForm] = useState(false);
  const [editingProduct, setEditingProduct] = useState(null);
  const [productForm, setProductForm] = useState({
    productName: '', productDescription: '', productPrice: '', stockQuantity: '', category: '', productOffer: 0
  });

  useEffect(() => {
    loadAll();
  }, []);

  const loadAll = async () => {
    try {
      const [p, u, o] = await Promise.all([
        productService.getAllProducts(),
        userService.getAllUsers(),
        orderService.getAllOrders(),
      ]);
      setProducts(p || []);
      setUsers(u || []);
      setOrders(o || []);
    } catch {}
  };

  const handleProductSubmit = async () => {
    try {
      if (editingProduct) {
        await productService.updateProduct(editingProduct.productId || editingProduct.product_id, productForm);
        toast.success('Product updated!');
      } else {
        await productService.createProduct(productForm);
        toast.success('Product added!');
      }
      setShowProductForm(false);
      setEditingProduct(null);
      setProductForm({ productName: '', productDescription: '', productPrice: '', stockQuantity: '', category: '', productOffer: 0 });
      await loadAll();
    } catch { toast.error('Failed to save product'); }
  };

  const handleDeleteProduct = async (id) => {
    if (!window.confirm('Delete this product?')) return;
    try {
      await productService.deleteProduct(id);
      toast.success('Product deleted');
      await loadAll();
    } catch { toast.error('Failed to delete'); }
  };

  const handleEdit = (p) => {
    setEditingProduct(p);
    setProductForm({
      productName: p.productName || p.product_name,
      productDescription: p.productDescription || p.product_description,
      productPrice: p.productPrice || p.product_price,
      stockQuantity: p.stockQuantity || p.stock_quantity,
      category: p.category,
      productOffer: p.productOffer || p.product_offer || 0,
    });
    setShowProductForm(true);
  };

  const revenue = orders.filter(o => (o.paymentStatus || o.payment_status) === 'PAID')
    .reduce((sum, o) => sum + (o.totalAmount || o.total_amount || 0), 0);

  return (
    <div className="admin-page">
      <div className="admin-sidebar">
        <div className="admin-logo">🌿 Admin Panel</div>
        {['dashboard', 'products', 'users', 'orders'].map(tab => (
          <button
            key={tab}
            className={`admin-nav-btn ${activeTab === tab ? 'active' : ''}`}
            onClick={() => setActiveTab(tab)}
          >
            {tab === 'dashboard' ? '📊' : tab === 'products' ? '🛒' : tab === 'users' ? '👥' : '📦'} {tab.charAt(0).toUpperCase() + tab.slice(1)}
          </button>
        ))}
      </div>

      <div className="admin-content">
        {activeTab === 'dashboard' && (
          <div className="admin-dashboard">
            <h1>Dashboard Overview</h1>
            <div className="stats-grid">
              <div className="stat-card">
                <div className="stat-icon">🛒</div>
                <div className="stat-info">
                  <span>{products.length}</span>
                  <p>Total Products</p>
                </div>
              </div>
              <div className="stat-card">
                <div className="stat-icon">👥</div>
                <div className="stat-info">
                  <span>{users.length}</span>
                  <p>Registered Users</p>
                </div>
              </div>
              <div className="stat-card">
                <div className="stat-icon">📦</div>
                <div className="stat-info">
                  <span>{orders.length}</span>
                  <p>Total Orders</p>
                </div>
              </div>
              <div className="stat-card revenue">
                <div className="stat-icon">💰</div>
                <div className="stat-info">
                  <span>₹{revenue.toFixed(0)}</span>
                  <p>Total Revenue</p>
                </div>
              </div>
            </div>
            <div className="recent-orders">
              <h2>Recent Orders</h2>
              <table className="admin-table">
                <thead><tr><th>Order ID</th><th>Amount</th><th>Status</th><th>Payment</th></tr></thead>
                <tbody>
                  {orders.slice(0, 5).map(o => (
                    <tr key={o.orderId || o.order_id}>
                      <td>#{o.orderId || o.order_id}</td>
                      <td>₹{(o.totalAmount || o.total_amount || 0).toFixed(2)}</td>
                      <td><span className="status-pill">{o.orderStatus || o.order_status}</span></td>
                      <td><span className={`pay-status ${(o.paymentStatus || o.payment_status)?.toLowerCase()}`}>{o.paymentStatus || o.payment_status}</span></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {activeTab === 'products' && (
          <div className="admin-products">
            <div className="admin-section-header">
              <h1>Products ({products.length})</h1>
              <button className="btn-add" onClick={() => { setShowProductForm(true); setEditingProduct(null); }}>+ Add Product</button>
            </div>
            {showProductForm && (
              <div className="product-form-card">
                <h3>{editingProduct ? 'Edit Product' : 'Add New Product'}</h3>
                <div className="form-grid">
                  <div className="form-group"><label>Name</label><input value={productForm.productName} onChange={e => setProductForm({ ...productForm, productName: e.target.value })} /></div>
                  <div className="form-group"><label>Category</label><input value={productForm.category} onChange={e => setProductForm({ ...productForm, category: e.target.value })} /></div>
                  <div className="form-group"><label>Price (₹)</label><input type="number" value={productForm.productPrice} onChange={e => setProductForm({ ...productForm, productPrice: e.target.value })} /></div>
                  <div className="form-group"><label>Stock</label><input type="number" value={productForm.stockQuantity} onChange={e => setProductForm({ ...productForm, stockQuantity: e.target.value })} /></div>
                  <div className="form-group"><label>Offer (%)</label><input type="number" value={productForm.productOffer} onChange={e => setProductForm({ ...productForm, productOffer: e.target.value })} /></div>
                  <div className="form-group full-width"><label>Description</label><textarea value={productForm.productDescription} onChange={e => setProductForm({ ...productForm, productDescription: e.target.value })} /></div>
                </div>
                <div className="form-actions">
                  <button className="btn-save" onClick={handleProductSubmit}>Save</button>
                  <button className="btn-cancel" onClick={() => setShowProductForm(false)}>Cancel</button>
                </div>
              </div>
            )}
            <table className="admin-table">
              <thead><tr><th>Name</th><th>Category</th><th>Price</th><th>Stock</th><th>Offer</th><th>Actions</th></tr></thead>
              <tbody>
                {products.map(p => (
                  <tr key={p.productId || p.product_id}>
                    <td>{p.productName || p.product_name}</td>
                    <td><span className="cat-tag">{p.category}</span></td>
                    <td>₹{(p.productPrice || p.product_price || 0).toFixed(2)}</td>
                    <td>{p.stockQuantity || p.stock_quantity}</td>
                    <td>{(p.productOffer || p.product_offer || 0)}%</td>
                    <td>
                      <button className="btn-edit-sm" onClick={() => handleEdit(p)}>✏️ Edit</button>
                      <button className="btn-delete-sm" onClick={() => handleDeleteProduct(p.productId || p.product_id)}>🗑️ Delete</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {activeTab === 'users' && (
          <div className="admin-users">
            <h1>Users ({users.length})</h1>
            <table className="admin-table">
              <thead><tr><th>Name</th><th>Email</th><th>Phone</th><th>Role</th></tr></thead>
              <tbody>
                {users.map(u => (
                  <tr key={u.userId || u.user_id}>
                    <td>{u.name}</td>
                    <td>{u.email}</td>
                    <td>{u.phoneNo || u.phone_no || '-'}</td>
                    <td><span className={`role-tag ${u.role?.toLowerCase()}`}>{u.role}</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {activeTab === 'orders' && (
          <div className="admin-orders">
            <h1>Orders ({orders.length})</h1>
            <table className="admin-table">
              <thead><tr><th>Order ID</th><th>User ID</th><th>Amount</th><th>Status</th><th>Payment</th><th>Date</th></tr></thead>
              <tbody>
                {orders.map(o => (
                  <tr key={o.orderId || o.order_id}>
                    <td>#{o.orderId || o.order_id}</td>
                    <td>User #{o.userId || o.user_id}</td>
                    <td>₹{(o.totalAmount || o.total_amount || 0).toFixed(2)}</td>
                    <td><span className="status-pill">{o.orderStatus || o.order_status}</span></td>
                    <td><span className={`pay-status ${(o.paymentStatus || o.payment_status)?.toLowerCase()}`}>{o.paymentStatus || o.payment_status}</span></td>
                    <td>{new Date(o.orderDate || o.order_date).toLocaleDateString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;
